      function CF_PROTOCOL_CASEFormula return Char is
V_STRING VARCHAR2(200);
V_PROTOCOL_NO     PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_NO%TYPE;
V_PROTOCOL_DATE   PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_DATE%TYPE;


--SPAP 12/2020 EMAIL BY 02/12/2020 PSYCHOGIOS
CURSOR C_PROTOCOL IS
SELECT A.pai_application_incr_seq_no||'-'||TO_CHAR(B.APPL_DATE,'DD/MM/RRRR')
FROM PEN_DECISION_INSTANCE A,
	   PEN_APPLICATION_INSTANCES B 										 
WHERE A.DEC_INCR_SEQ_NO                = :P_DECISION_NO
  AND A.DT_DEC_UNIT_CODE               = :P_DT_DEC_UNIT_CODE  
	AND A.DT_DECISION_YEAR               = :P_DT_DECISION_YEAR  
	AND A.DT_DOCUMENT_TYPE_DEC_CODE      = '1' 
	AND A.PAI_PDTA_APPLICATION_UNIT_CODE = B.PDTA_APPLICATION_UNIT_CODE
  AND A.PAI_PDTA_APPLICATION_YEAR      = B.PDTA_APPLICATION_YEAR
  AND A.PAI_APPLICATION_INCR_SEQ_NO    = B.APPLICATION_INCR_SEQ_NO;

V_PROT VARCHAR2(100);
--SPAP

begin

  OPEN C_PROTOCOL;
  FETCH C_PROTOCOL INTO V_PROT;
  CLOSE C_PROTOCOL;


  IF :CF_AWARD_FLG!='0' THEN 
	  SELECT A.CONVERT_PROTOCOL_NO ,
		       A.CONVERT_PROTOCOL_DATE
	  INTO V_PROTOCOL_NO,
	       V_PROTOCOL_DATE
		FROM PEN_DECISION_INSTANCE A										 
		WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
		AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE_DIR
		AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
		AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';
 END IF;
	
IF :CF_AWARD_FLG='0' THEN 
	IF :PROTOCOL_NO IS NOT NULL THEN 
     --V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση για ' ; -- SPAP 12/2020
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROT || ' αίτηση για ';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,' ;
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση για  ';
  END IF;    
ELSE
 	IF V_PROTOCOL_NO IS NOT NULL THEN 
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROTOCOL_NO ||'-'||V_PROTOCOL_DATE || ' αίτηση για ' ;
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση για ';
  END IF;    
END IF;
  return (V_STRING);
end;

