      function CF_REDUCTION_267Formula return Char is

SF507_VALUE NUMBER;
SF508_VALUE NUMBER;
SF499_VALUE CHAR(50);

CURSOR CUR_SF499 IS
SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00499';


CURSOR cur_SF00507 IS 
 SELECT A.VALUE
 FROM  PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00507';

CURSOR cur_SF00508 IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00508';

	v_denominator		 NUMBER;
	CURSOR cur_age_reduction_denom IS
	SELECT denominator
	FROM PEN_AGE_REDUCTION_DENOM
	WHERE VALIDITY_DATE <= :CF_INS_DATE
	ORDER BY VALIDITY_DATE DESC;


begin

  OPEN CUR_SF499;
  FETCH CUR_SF499
  INTO SF499_VALUE;
  CLOSE CUR_SF499;

	IF SF499_VALUE = '00001' THEN 
 		  	OPEN cur_SF00507;
		  	FETCH cur_SF00507
		  	INTO SF507_VALUE;
		  	CLOSE cur_SF00507;

				OPEN cur_age_reduction_denom;
				FETCH cur_age_reduction_denom
				INTO v_denominator;
				CLOSE cur_age_reduction_denom;

--		  IF :CF_INS_DATE >= TO_DATE('1/1/2003','DD/MM/RRRR') THEN 
		  	IF SF507_VALUE IS NOT NULL THEN 
  		  	RETURN (TO_CHAR(SF507_VALUE)||'/'||v_denominator);
		  	ELSE 
		  		RETURN ' ';
        END IF;
/*		  ELSE 
		    IF SF507_VALUE IS NOT NULL THEN 		
	   	  	RETURN (TO_CHAR(SF507_VALUE)||'/200');
		    ELSE
		      RETURN ' ';	
        END IF;
		  END IF;*/
	ELSE
 		  	OPEN cur_SF00508;
		  	FETCH cur_SF00508
		  	INTO SF508_VALUE;
		  	CLOSE cur_SF00508;

        IF SF508_VALUE IS NOT NULL THEN  		  	
  		  	RETURN TO_CHAR(SF508_VALUE) || '%';
        ELSE
        	RETURN ' ';	
        END IF;
  END IF;
end;

      function CF_SF509Formula return Char is

V_DESCR   VARCHAR2(50);

CURSOR CUR_PENSION_REASON IS
SELECT B.REASON_DESCR 
FROM PEN_DEC_FACT_TYPES_INSTANCE A, PEN_DEATH_REASON B
WHERE A.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_DIR
AND A.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_DIR 
AND A.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_DIR 
AND A.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1'
AND A.INS_INSURED_ID = :P_INSURED_ID
AND A.TITLE_CODE = '00367'
AND A.DEC_FACT_TYPE_CODE = '00509'
AND A.VALUE =B.REASON_CODE;

begin
  
  OPEN CUR_PENSION_REASON;
  FETCH CUR_PENSION_REASON
  INTO V_DESCR;
  CLOSE CUR_PENSION_REASON;
  
  RETURN V_DESCR;

end;

