      FUNCTION CF_PROCCESS_IDFormula RETURN NUMBER IS

V_PROCESS_ID NUMBER;

CURSOR CUR_PROCESS IS
SELECT A.PROCESS_ID
FROM PEN_SUMMARIZATION_PER_INSURED A
WHERE A.INSURED_ID = :P_INSURED_ID
ORDER BY A.PROCESS_ID DESC;

BEGIN
	
	OPEN CUR_PROCESS;
	FETCH CUR_PROCESS
	INTO V_PROCESS_ID;
	CLOSE CUR_PROCESS;
	
  :P_PROCESS_ID:=V_PROCESS_ID;
  RETURN :P_PROCESS_ID;
END;

      

FUNCTION CF_YEARS_USEDFormula RETURN CHAR IS

TYPE T_YEARS_USED IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
YEARS T_YEARS_USED ;
I NUMBER:=1;
LINE VARCHAR2(200) :=''; --CONTAINTS YEARS WITH FORM 1999,2000,2001

CURSOR CUR_YEARS_USED IS
SELECT A.YEAR_USED
FROM PEN_SUMMAR_CLASS_YEARS A 
WHERE A.PROCESS_ID = :P_PROCESS_ID;

BEGIN
  
  OPEN CUR_YEARS_USED;

   LOOP
	  FETCH CUR_YEARS_USED
	  INTO YEARS(I);
	  I:= I+1;
	  EXIT WHEN CUR_YEARS_USED%NOTFOUND;  
   END LOOP;

  FOR K IN 1..YEARS.COUNT LOOP
  IF k!=years.COUNT THEN 
     LINE := LINE || TO_CHAR(YEARS(K)) || ',';     
  ELSE
    LINE := LINE || TO_CHAR(YEARS(K));     
  END IF;
  END LOOP;
  
  CLOSE CUR_YEARS_USED;
  
  RETURN LINE;
  
END;

      function CF_TERMINATION_TRI_YEARSForm return Date is

V_RESULT DATE;

CURSOR cur_DATE IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00315' AND
	     A.Dec_Fact_Type_Code = '00059';

begin

  IF :DATE_OF_DEATH IS NOT NULL THEN 
  	RETURN LAST_DAY(ADD_MONTHS(:DATE_OF_DEATH,36))+1;
  ELSE
		  OPEN cur_DATE;
		  FETCH cur_DATE
		  INTO V_RESULT;
		  CLOSE cur_DATE;

      RETURN LAST_DAY(ADD_MONTHS(V_RESULT,36))+1;  

  END IF;
  
END;

      function CF_SEX_DEADFormula return Char is
V_SEX VARCHAR2(20);
begin
  
  SELECT DECODE(SEX,'Α','ΤΟΥ ΘΑΝΟΝΤΟΣ','Θ','ΤΗΣ ΘΑΝΟΥΣΗΣ')
  INTO V_SEX
  FROM REG_INSURED 
  WHERE INSURED_ID = :P_INSURED_ID;
  
  RETURN V_SEX;
end;

      function CF_INSURED_IND_PLUS65Formula return Date is
 V_BIRTH_DATE DATE;
begin
  /*FIND INDIRECT MEMBER DATE OF DEATH +  65 YEARS*/
  SELECT DATE_OF_BIRTH
  INTO V_BIRTH_DATE
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID_IND;
 
  RETURN ADD_MONTHS(V_BIRTH_DATE,65*12);
 
end;

      function CF_COMPARE_DATESFormula return Char is
 
 V_CHAR VARCHAR2(10);
 
begin
  IF :CF_INSURED_IND_PLUS65  <= :CF_TERMINATION_TRI_YEARS THEN 
      V_CHAR := '30%';
  ELSIF :CF_INSURED_IND_PLUS65  > :CF_TERMINATION_TRI_YEARS THEN
  	  V_CHAR := '50%';
  END IF;
  
  RETURN V_CHAR;
end;

      FUNCTION CF_PERSON_NAMEFormula RETURN CHAR IS

 v_Psv_user_id VARCHAR2(15);
 V_PERSON_NAME VARCHAR2(100);

Cursor cur_Psv_user_id is 
SELECT Created_By
FROM PEN_DECISION_INSTANCE
WHERE  PEN_DECISION_INSTANCE.Dec_Incr_Seq_No=:P_DECISION_NO
AND PEN_DECISION_INSTANCE.Dt_Dec_Unit_Code=:P_Dt_Dec_Unit_Code
AND PEN_DECISION_INSTANCE.Dt_Decision_Year=:P_Dt_Decision_Year
AND PEN_DECISION_INSTANCE.Dt_Document_Type_Dec_Code='1';

begin
   --Psv_User_Id    := Sec_Appl_Pkg.Get_Current_User(:P_Login_Id);
   
   	OPEN cur_Psv_user_id;
	  FETCH cur_Psv_user_id
	  INTO v_Psv_user_id;
	  CLOSE cur_Psv_user_id;

   SELECT PERSON_SURNAME || ' ' ||PERSON_NAME
   INTO V_PERSON_NAME
   FROM SEC_USERS  
   WHERE USER_ID = v_Psv_user_id;

   RETURN V_PERSON_NAME; 
end;

