      function CF_DEBT_DESCRFormula return Char is
TO_RETURN VARCHAR2(1000);

CURSOR C1 IS
 SELECT PRCN_DESCR
   FROM PPI_PEN_DEBTS_PRCN
  WHERE PRCN= :DEDUCTION_PENSION_FACTOR;
  
v_temp_cnt number          ;
  
V_PRCN_DESCR VARCHAR2(200);  
begin
  if :debt_id='31' then
  	to_return:=:num_debt||'. '||'Συμψηφίζεται '||:descr||' Συνολικού Ποσού: '||:TOTAL_DEDUCTION_AMMOUNT ||' ΕΥΡΩ';
  else
  	OPEN C1;
  	FETCH C1 INTO V_PRCN_DESCR;
  	CLOSE C1;
  	to_return:='Παρακράτηση ';
  	if :DOSAGE_AMOUNT is not null then 
  			to_return:=:num_debt||'. '||to_return||' ποσού '||:DOSAGE_AMOUNT||' ΕΥΡΩ της μηνιαίας Σύνταξης ';
  	else
  			to_return:=:num_debt||'. '||to_return||' ποσοστού '||V_PRCN_DESCR||' της μηνιαίας Σύνταξης ';
  	end if;		
  		to_return:=to_return||' για '||:descr||' από Συνολικό Ποσό: '||:TOTAL_DEDUCTION_AMMOUNT ||' ΕΥΡΩ';
  end if;	
  return TO_RETURN;
end;

      function CF_stoixeia_paymentsFormula return Char is

to_return varchar2(500);
v_iban      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
select distinct pen_dec_fact_types_instance.value
from  pen_dec_fact_types_instance
