      function CF_AVERAGE_INCOMEFormula return Number is

 v_calc_begin_date_varchar    NUMBER;
                                     
v_date_672 varchar2(10);
v_date_673 varchar2(10);

begin
  
  v_date_672 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR_DIR,
                                             :P_DT_DEC_UNIT_CODE_DIR,
                                             :P_DT_INCR_SEC_NO_DIR, 
                                             '1',
                                             0,
                                             0,
                                             '00001',
                                             '00636',
                                             '00672');
  
  v_date_673 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                              :P_DT_DECISION_YEAR_DIR,
                                             :P_DT_DEC_UNIT_CODE_DIR,
                                             :P_DT_INCR_SEC_NO_DIR, 
                                             '1',
                                             0,
                                             0,
                                             '00001',
                                             '00636',
                                             '00673');
  
  
  
  v_calc_begin_date_varchar := NVL(v_date_672,0)+NVL(v_date_673,0);
  
 IF v_calc_begin_date_varchar = 0 THEN 
v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
             0,0,'00001','01180','00651');


END IF;

  RETURN v_calc_begin_date_varchar;
end;

