      function CF_24Formula return CHAR is


v_DESCR   VARCHAR2(50);
v_calc_begin_date_varchar   VARCHAR2(10);


begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,
																												 :P_DT_DECISION_YEAR_DIR,
																												 :P_DT_DEC_UNIT_CODE_DIR,
																												 :P_DT_INCR_SEC_NO_DIR, 
																												 '1',
                                                          0,
                                                          0,
                                                          '00001',
                                                          '01180',
                                                          '00010');

	IF v_calc_begin_date_varchar IS NOT NULL THEN 
		
		SELECT  PENSION_INST_NAME
		 INTO   v_DESCR
		 FROM   COM_PENSION_INSTITUTIONS
		 WHERE   PENSION_INST_CODE = v_calc_begin_date_varchar;
		
		 RETURN V_DESCR;
	ELSE
		RETURN '';
	END IF;
		
 EXCEPTION WHEN OTHERS THEN NULL;
 
end;

