if nvl(v_date_char,'0') = '0' then v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '01636', '00641'); end if;
v_ymd := v_ymd||nvl(v_date_char,'0')||'-';
v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00639', '00686');
if nvl(v_date_char,'0') = '0' then v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00638', '00679'); end if;
