function CF_51Formula return Char is v_char VARCHAR2(10); v_char_descr VARCHAR2(200);
CURSOR CUR IS SELECT PERCENTAGE||' % '--DESCR||' : '||PERCENTAGE||' % ' FROM PEN_SICKNESS_DEDUCTIONS_NEW WHERE SICKNESS_DEDUCTION_ID= v_char AND EFFECTIVE_DATE <= NVL(:P_FACTITIOUS_DATE, SYSDATE) ORDER BY EFFECTIVE_DATE DESC;
CURSOR CUR_FACT_TYPES IS SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '00159' AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :P_Insured_Id_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' UNION SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '01069' AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :P_Insured_Id_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' UNION SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE, PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE FROM pen_dec_fact_types_instance, PEN_SICKNESS_DEDUCTIONS_NEW WHERE pen_dec_fact_types_instance.title_code = '99111' ---EE-DS AND pen_dec_fact_types_instance.dec_fact_type_code = '00228' AND pen_dec_fact_types_instance.ins_insured_id = :P_Insured_Id_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.VALUE = PEN_SICKNESS_DEDUCTIONS_NEW.SICKNESS_DEDUCTION_ID(+) AND :P_ACC_START_DATE >= PEN_SICKNESS_DEDUCTIONS_NEW.EFFECTIVE_DATE AND pen_dec_fact_types_instance.STATUS = '1' ORDER BY 2 DESC ;
L_EFFECTIVE_DATE DATE;
begin /* CHRYS 10/1/2018 v_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '00001', '01069', '00674');
/* CHRYS 10/1/2018 */ /* v_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND, :P_DT_DECISION_YEAR_SR, :P_DT_DEC_UNIT_CODE_SR, :P_DT_INCR_SEC_NO_SR, '1', 0, 0, '00001', '01069', '00228');*/
OPEN CUR; FETCH CUR INTO v_char_descr; CLOSE CUR;
IF v_char_descr IS NULL THEN OPEN CUR_FACT_TYPES; FETCH CUR_FACT_TYPES INTO v_char_descr, L_EFFECTIVE_DATE; CLOSE CUR_FACT_TYPES;
IF ( v_char_descr IS NOT NULL AND v_char_descr = 0 ) THEN v_char_descr:='ΚΑΙ ΧΩΡΙΣ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ. '; ELSE v_char_descr :='ΠΟΥ ΥΠΟΚΕΙΤΑΙ ΣΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||v_char_descr||'% ΚΑΙ ΣΕ ΟΛΕΣ ΤΙΣ ΝΟΜΙΜΕΣ ΚΡΑΤΗΣΕΙΣ.'; END IF; END IF;
RETURN NVL(v_char_descr,' '); EXCEPTION WHEN OTHERS THEN RETURN NULL; end;

